'use strict';

const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = 3000;
const PREMBLY_NIN_URL = 'https://api.prembly.com/verification/nin';

/**
 * POST /api/wallet/create
 *
 * Body:
 *   ninNumber       {string} - The user's National Identity Number
 *   faceLivelinessRef {string} - Reference ID from a completed face liveliness session
 *
 * Responses:
 *   201 { wallet_id: "new_wallet_123" }  - NIN verified, wallet created
 *   400 { error: string }                - Verification failed or bad input
 *   500 { error: string }                - Upstream / server error
 */
app.post('/api/wallet/create', async (req, res) => {
  const { ninNumber, faceLivelinessRef } = req.body;

  // ── 1. Validate required fields ──────────────────────────────────────────
  if (!ninNumber || !faceLivelinessRef) {
    return res.status(400).json({
      error: 'ninNumber and faceLivelinessRef are required.',
    });
  }

  // ── 2. Read Prembly credentials from environment ──────────────────────────
  const appId = process.env.PREMBLY_APP_ID;
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!appId || !apiKey) {
    console.error('[wallet/create] Missing Prembly credentials in environment.');
    return res.status(500).json({
      error: 'Server misconfiguration: Prembly credentials are not set.',
    });
  }

  // ── 3. Verify NIN with Prembly ────────────────────────────────────────────
  let premblyResponse;
  try {
    premblyResponse = await axios.post(
      PREMBLY_NIN_URL,
      { number: ninNumber },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
          'Content-Type': 'application/json',
        },
      }
    );
  } catch (err) {
    // Axios throws on 4xx / 5xx — treat upstream errors as verification failure
    const status = err.response?.status;
    const message = err.response?.data?.detail || err.response?.data?.message || err.message;

    console.error(`[wallet/create] Prembly NIN verification error (HTTP ${status}):`, message);

    if (status && status >= 400 && status < 500) {
      return res.status(400).json({
        error: `NIN verification failed: ${message}`,
      });
    }

    return res.status(500).json({
      error: `Upstream verification service error: ${message}`,
    });
  }

  // ── 4. Inspect Prembly verification result ────────────────────────────────
  //
  // Prembly returns a top-level `status` boolean and a `verification.status`
  // string ("VERIFIED" / "NOT_VERIFIED") in a successful HTTP 200 response.
  // We accept the NIN only when both signals confirm success.
  const data = premblyResponse.data;
  const verified =
    data?.status === true &&
    data?.verification?.status?.toUpperCase() === 'VERIFIED';

  if (!verified) {
    console.warn('[wallet/create] NIN not verified:', JSON.stringify(data));
    return res.status(400).json({
      error: 'NIN verification was unsuccessful. Wallet creation denied.',
    });
  }

  // ── 5. Create the wallet ──────────────────────────────────────────────────
  //
  // In a production system you would persist the wallet here (database, etc.).
  // For this implementation we return the static wallet ID as specified.
  console.info('[wallet/create] NIN verified successfully. Creating wallet.');
  return res.status(201).json({ wallet_id: 'new_wallet_123' });
});

// ── Health-check (convenience) ────────────────────────────────────────────────
app.get('/health', (_req, res) => res.json({ status: 'ok' }));

// ── Start server ──────────────────────────────────────────────────────────────
app.listen(PORT, () => {
  console.log(`[fintech-app] Server listening on port ${PORT}`);
});

module.exports = app; // exported for testing

